import{_ as a,o as e,c as s,ag as n}from"./chunks/framework.8qlNDhri.js";const c=JSON.parse('{"title":"AI 配置指南","description":"在 Narrafiilm 中配置 AI 提供商（DeepSeek / OpenAI / Claude / Qwen 等）的方法。","frontmatter":{"title":"AI 配置指南","description":"在 Narrafiilm 中配置 AI 提供商（DeepSeek / OpenAI / Claude / Qwen 等）的方法。"},"headers":[],"relativePath":"guide/ai-configuration.md","filePath":"guide/ai-configuration.md","lastUpdated":1776504851000}'),d={name:"guide/ai-configuration.md"};function p(i,t,r,o,l,h){return e(),s("div",null,[...t[0]||(t[0]=[n(`<h1 id="ai-配置指南" tabindex="-1">AI 配置指南 <a class="header-anchor" href="#ai-配置指南" aria-label="Permalink to &quot;AI 配置指南&quot;">​</a></h1><p>Narrafiilm 支持多个 AI 提供商，按用途分为视频理解和解说生成两个维度。</p><hr><h2 id="快速配置" tabindex="-1">快速配置 <a class="header-anchor" href="#快速配置" aria-label="Permalink to &quot;快速配置&quot;">​</a></h2><p>只需配置 <strong>DeepSeek API Key</strong> 即可完整运行。获取地址：<a href="https://platform.deepseek.com" target="_blank" rel="noreferrer">platform.deepseek.com</a></p><div class="language-env vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">env</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>DEEPSEEK_API_KEY=sk-xxxxxxxxxxxxxxxxxxxxxxxx</span></span></code></pre></div><p>在应用内：设置 → AI 配置 → 粘贴 Key → 保存 → 连接测试</p><hr><h2 id="视频理解模型-场景分析" tabindex="-1">视频理解模型（场景分析） <a class="header-anchor" href="#视频理解模型-场景分析" aria-label="Permalink to &quot;视频理解模型（场景分析）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>提供商</th><th>模型</th><th>说明</th></tr></thead><tbody><tr><td><strong>阿里云百炼</strong></td><td>Qwen2.5-VL (7B/72B)</td><td>默认，视频理解 SOTA</td></tr><tr><td><strong>OpenAI</strong></td><td>GPT-4.1</td><td>多模态，能力强</td></tr><tr><td><strong>Google</strong></td><td>Gemini 2.5 Flash</td><td>性价比高</td></tr></tbody></table><h3 id="阿里云百炼配置" tabindex="-1">阿里云百炼配置 <a class="header-anchor" href="#阿里云百炼配置" aria-label="Permalink to &quot;阿里云百炼配置&quot;">​</a></h3><div class="language-env vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">env</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>DASHSCOPE_API_KEY=sk-xxxxxxxxxxxxxxxx</span></span></code></pre></div><p>在应用中设置 → AI 配置 → 阿里云百炼 → 填入 Key</p><h3 id="openai-配置" tabindex="-1">OpenAI 配置 <a class="header-anchor" href="#openai-配置" aria-label="Permalink to &quot;OpenAI 配置&quot;">​</a></h3><div class="language-env vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">env</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>OPENAI_API_KEY=sk-xxxxxxxxxxxxxxxx</span></span>
<span class="line"><span>OPENAI_MODEL=gpt-4.1</span></span></code></pre></div><hr><h2 id="解说生成模型-文稿撰写" tabindex="-1">解说生成模型（文稿撰写） <a class="header-anchor" href="#解说生成模型-文稿撰写" aria-label="Permalink to &quot;解说生成模型（文稿撰写）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>提供商</th><th>模型</th><th>说明</th></tr></thead><tbody><tr><td><strong>DeepSeek</strong></td><td>DeepSeek-V3.2</td><td>默认，性价比最高</td></tr><tr><td><strong>OpenAI</strong></td><td>GPT-4.1</td><td>最强通用能力</td></tr><tr><td><strong>Anthropic</strong></td><td>Claude Opus 4.6</td><td>超长上下文</td></tr><tr><td><strong>阿里云</strong></td><td>Qwen2.5-Max</td><td>中文优化</td></tr></tbody></table><h3 id="deepseek-配置-默认" tabindex="-1">DeepSeek 配置（默认） <a class="header-anchor" href="#deepseek-配置-默认" aria-label="Permalink to &quot;DeepSeek 配置（默认）&quot;">​</a></h3><div class="language-env vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">env</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>DEEPSEEK_API_KEY=sk-xxxxxxxxxxxxxxxx</span></span>
<span class="line"><span>DEEPSEEK_MODEL=deepseek-chat</span></span></code></pre></div><h3 id="claude-配置" tabindex="-1">Claude 配置 <a class="header-anchor" href="#claude-配置" aria-label="Permalink to &quot;Claude 配置&quot;">​</a></h3><div class="language-env vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">env</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ANTHROPIC_API_KEY=sk-ant-xxxxxxxxxxxxxxxx</span></span>
<span class="line"><span>ANTHROPIC_MODEL=claude-opus-4.6-20260219</span></span></code></pre></div><hr><h2 id="配音合成" tabindex="-1">配音合成 <a class="header-anchor" href="#配音合成" aria-label="Permalink to &quot;配音合成&quot;">​</a></h2><table tabindex="0"><thead><tr><th>引擎</th><th>配置</th><th>说明</th></tr></thead><tbody><tr><td><strong>Edge-TTS</strong>（默认）</td><td>无需 Key</td><td>免费，多音色</td></tr><tr><td><strong>F5-TTS</strong></td><td>需安装</td><td>零样本克隆</td></tr><tr><td><strong>OpenAI TTS</strong></td><td>需 OpenAI Key</td><td>超自然语音</td></tr></tbody></table><p>Edge-TTS 无需任何配置，开箱即用。</p><hr><h2 id="环境变量方式" tabindex="-1">环境变量方式 <a class="header-anchor" href="#环境变量方式" aria-label="Permalink to &quot;环境变量方式&quot;">​</a></h2><p>所有配置也可以通过 <code>.env</code> 文件管理（放在项目根目录，已加入 .gitignore）：</p><div class="language-env vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">env</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># DeepSeek（解说生成，默认）</span></span>
<span class="line"><span>DEEPSEEK_API_KEY=sk-xxx</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 阿里云百炼（视频理解）</span></span>
<span class="line"><span>DASHSCOPE_API_KEY=sk-xxx</span></span>
<span class="line"><span></span></span>
<span class="line"><span># OpenAI（可选全栈）</span></span>
<span class="line"><span>OPENAI_API_KEY=sk-xxx</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 配音引擎：edge-tts（默认）/ f5-tts / openai</span></span>
<span class="line"><span>TTS_ENGINE=edge-tts</span></span></code></pre></div><hr><h2 id="多提供商组合建议" tabindex="-1">多提供商组合建议 <a class="header-anchor" href="#多提供商组合建议" aria-label="Permalink to &quot;多提供商组合建议&quot;">​</a></h2><table tabindex="0"><thead><tr><th>场景</th><th>视频理解</th><th>解说生成</th><th>成本</th></tr></thead><tbody><tr><td><strong>免费入门</strong></td><td>Qwen2.5-VL（本地）</td><td>DeepSeek-V3.2</td><td>接近零</td></tr><tr><td><strong>日常创作</strong></td><td>Qwen2.5-VL（API）</td><td>DeepSeek-V3.2</td><td>低</td></tr><tr><td><strong>最高质量</strong></td><td>GPT-4.1</td><td>Claude Opus 4.6</td><td>高</td></tr></tbody></table>`,33)])])}const g=a(d,[["render",p]]);export{c as __pageData,g as default};
